export function ExpertiseIcon({
  id,
  className,
}: {
  id: ExpertiseIconId;
  className?: string;
}) {
  switch (id) {
    case "code":
      return <CodeBracketIcon className={className} />;
    case "ai":
      return <AiMlIcon className={className} />;
    case "web3":
      return <Web3Icon className={className} />;
  }
}
